import json

with open("system_a.json") as f: a_data = json.load(f)
with open("system_b.json") as f: b_data = json.load(f)
with open("reconciled.json") as f: rec_data = json.load(f)

A_RECS = {r["subscriber_id"]: r for r in a_data}
B_RECS = {r["subscriber_id"]: r for r in b_data}
RECS = {r["subscriber_id"]: r for r in rec_data}

def walkthrough(rid, scenario):
    a = A_RECS.get(rid, {})
    b = B_RECS.get(rid, {})
    rec = RECS[rid]

    print(f"\n{'='*70}")
    print(f"EDGE CASE: {rid} — {scenario}")
    print(f"{'='*70}")
    print(f"System A last_updated: {a.get('last_updated', 'N/A')}")
    print(f"System B last_updated: {b.get('last_updated', 'N/A')}")
    print(f"System B manual_override: {b.get('manual_override', 'N/A')}")
    print()

    A_OWNED = ['username', 'email', 'display_name', 'auth_provider']
    B_OWNED = ['plan_id', 'renewal_date', 'seats', 'discount_pct']
    SHARED = ['account_status', 'timezone']

    print(f"{'Field':<20} {'A Value':<22} {'B Value':<22} {'Reconciled':<22} {'Expected':<22} {'Verdict'}")
    print("-" * 110)

    for f in ['subscriber_id'] + A_OWNED + B_OWNED + SHARED + ['reconcile_source']:
        a_val = str(a.get(f, 'N/A')) if a.get(f) is not None else 'null'
        b_val = str(b.get(f, 'N/A')) if b.get(f) is not None else 'null'
        rec_val = str(rec.get(f)) if rec.get(f) is not None else 'null'

        # Determine expected
        if f == 'subscriber_id':
            expected = rid
        elif f == 'reconcile_source':
            if b.get('manual_override') == True:
                expected = 'manual_override'
            elif a and not b:
                expected = 'system_a_only'
            elif b and not a:
                expected = 'system_b_only'
            else:
                expected = 'merged'
        elif f in A_OWNED:
            if b.get('manual_override') == True:
                expected = str(b.get(f)) if b.get(f) is not None else 'null'
            elif a:
                expected = str(a.get(f)) if a.get(f) is not None else 'null'
            else:
                expected = 'null'
        elif f in B_OWNED:
            if b.get('manual_override') == True:
                expected = str(b.get(f)) if b.get(f) is not None else 'null'
            elif b:
                expected = str(b.get(f)) if b.get(f) is not None else 'null'
            else:
                expected = 'null'
        elif f in SHARED:
            if b.get('manual_override') == True:
                expected = str(b.get(f)) if b.get(f) is not None else 'null'
            elif a and b:
                ts_a = a.get('last_updated', '')
                ts_b = b.get('last_updated', '')
                if ts_a >= ts_b:
                    expected = str(a.get(f)) if a.get(f) is not None else 'null'
                else:
                    expected = str(b.get(f)) if b.get(f) is not None else 'null'
            elif a:
                expected = str(a.get(f)) if a.get(f) is not None else 'null'
            else:
                expected = str(b.get(f)) if b.get(f) is not None else 'null'

        verdict = "✓ PASS" if rec_val == expected else f"✗ FAIL"
        print(f"{f:<20} {a_val:<22} {b_val:<22} {rec_val:<22} {expected:<22} {verdict}")

# Edge Case 1: SUB-000009 — Non-override, B newer timestamp, field ownership + shared conflict
walkthrough("SUB-000009", "Both-present non-override, B newer timestamp → tests Rules 2 & 3 together")

# Edge Case 2: SUB-000010 — manual_override=true
walkthrough("SUB-000010", "Manual override → tests Rule 1 (B wins ALL fields)")

# Edge Case 3: SUB-000012 — System A only
walkthrough("SUB-000012", "System A only → tests Rule 4 (null-fill B fields)")

WALK_EOF

